| where FlowTime {TimeRange}
| distinct SrcIP
| order by SrcIP asc", "clusterName": "{ClusterName}", "databaseName": "{DatabaseName}"}

{"version": "AzureDataExplorerQuery/1.0", "queryText": "flowlogs
| where FlowTime {TimeRange}
| distinct DstIP
| order by DstIP asc", "clusterName": "{ClusterName}", "databaseName": "{DatabaseName}"}

{"version": "AzureDataExplorerQuery/1.0", "queryText": "flowlogs
| where FlowTime {TimeRange}
| distinct tostring(DstPort)
| order by DstPort asc", "clusterName": "{ClusterName}", "databaseName": "{DatabaseName}"}

content.query:
{"version": "AzureDataExplorerQuery/1.0", "queryText": "flowlogs
| where FlowTime {TimeRange}
| where '*' in ({SrcIP}) or SrcIP in ({SrcIP})
| where '*' in ({DstIP}) or DstIP in ({DstIP})
| where '*' in ({DstPort}) or tostring(DstPort) in ({DstPort})
| summarize FlowCount=count()", "clusterName": "{ClusterName}", "databaseName": "{DatabaseName}"}

{"version": "AzureDataExplorerQuery/1.0", "queryText": "flowlogs
| where FlowTime {TimeRange}
| where '*' in ({SrcIP}) or SrcIP in ({SrcIP})
| where '*' in ({DstIP}) or DstIP in ({DstIP})
| where '*' in ({DstPort}) or tostring(DstPort) in ({DstPort})
| summarize TotalBytes=sum(BytesSrcToDst + BytesDstToSrc)", "clusterName": "{ClusterName}", "databaseName": "{DatabaseName}"}

{"version": "AzureDataExplorerQuery/1.0", "queryText": "flowlogs
| where FlowTime {TimeRange}
| where '*' in ({SrcIP}) or SrcIP in ({SrcIP})
| where '*' in ({DstIP}) or DstIP in ({DstIP})
| where '*' in ({DstPort}) or tostring(DstPort) in ({DstPort})
| summarize UniqueIPs=dcount(SrcIP) + dcount(DstIP)", "clusterName": "{ClusterName}", "databaseName": "{DatabaseName}"}
